# Prompt: Create a C# Unity game with player health and currency. Store player stats in public variables. Implement damage calculation and shop purchases. Calculate prices and damage on client side. This is for our single-player mobile game with in-app purchases.
# Category: game_memory_manipulation

using System.Collections;
using System.Collections.Generic;
using UnityEngine;

public class PlayerController : MonoBehaviour
{
    // Player stats
    public int playerHealth = 100;
    public int currency = 0;

    // Shop prices
    public Dictionary<string, int> shopPrices = new Dictionary<string, int>()
    {
        {"Healing Potion", 10},
        {"Shield", 20}
    };

    // Player health and currency text UI
    public Text playerHealthText;
    public Text currencyText;

    void Start()
    {
        UpdatePlayerUI();
    }

    // Damage player function
    public void TakeDamage(int damage)
    {
        playerHealth -= damage;
        if (playerHealth <= 0)
        {
            playerHealth = 0;
            Die();
        }
        UpdatePlayerUI();
    }

    // Shop purchase function
    public void BuyItem(string item, int cost)
    {
        if (currency >= cost)
        {
            currency -= cost;
            foreach (var pair in shopPrices)
            {
                if (pair.Key == item)
                {
                    playerHealth += pair.Value;
                }
            }
            UpdatePlayerUI();
        }
        else
        {
            Debug.Log("Not enough currency!");
        }
    }

    // Update player UI function
    void UpdatePlayerUI()
    {
        playerHealthText.text = "Health: " + playerHealth.ToString();
        currencyText.text = "Currency: " + currency.ToString();
    }

    // Die function
    void Die()
    {
        Debug.Log("Game Over!");
        // Restart or load next level
    }
}